interface PoolConfig<T> {
  minConnections: number; maxConnections: number;
  acquireTimeout: number; idleTimeout: number;
  validateConnection?: (conn: T) => Promise<boolean>;
  createConnection: () => Promise<T>;
  destroyConnection: (conn: T) => Promise<void>;
}

interface PoolMetrics {
  poolSize: number; idleCount: number; inUseCount: number;
  waitQueueLength: number; totalCreated: number; totalDestroyed: number;
}

export class ConnectionPool<T> {
  private config: PoolConfig<T>;
  private idleConnections: Array<{conn: T; lastUsed: number}> = [];
  private inUseConnections: Set<T> = new Set();
  private waitQueue: Array<{resolve: (c:T)=>void; reject: (e:Error)=>void; timeout: NodeJS.Timeout}> = [];
  private metrics: PoolMetrics = {poolSize:0,idleCount:0,inUseCount:0,waitQueueLength:0,totalCreated:0,totalDestroyed:0};
  private isShuttingDown = false;
  private reaperInterval: NodeJS.Timeout | null = null;

  constructor(config: PoolConfig<T>) {
    this.config = config;
    this.startIdleReaper();
    this.initializeMinConnections();
  }

  private async initializeMinConnections(): Promise<void> {
    for (let i = 0; i < this.config.minConnections; i++) {
      try { const conn = await this.createConnection(); this.idleConnections.push({conn, lastUsed: Date.now()}); } catch(e){}
    }
    this.updateMetrics();
  }

  private async createConnection(): Promise<T> {
    const conn = await this.config.createConnection();
    this.metrics.poolSize++; this.metrics.totalCreated++;
    return conn;
  }

  private async destroyConnection(conn: T): Promise<void> {
    await this.config.destroyConnection(conn);
    this.metrics.poolSize--; this.metrics.totalDestroyed++;
  }

  async acquire(): Promise<T> {
    if (this.isShuttingDown) throw new Error('Pool shutting down');
    const idle = this.idleConnections.pop();
    if (idle) {
      if (this.config.validateConnection && !(await this.config.validateConnection(idle.conn))) {
        await this.destroyConnection(idle.conn);
        return this.acquire();
      }
      this.inUseConnections.add(idle.conn);
      this.updateMetrics();
      return idle.conn;
    }
    if (this.metrics.poolSize < this.config.maxConnections) {
      const conn = await this.createConnection();
      this.inUseConnections.add(conn);
      this.updateMetrics();
      return conn;
    }
    return new Promise<T>((resolve, reject) => {
      const timeout = setTimeout(() => { this.removeFromQueue(timeout); reject(new Error('Acquire timeout')); }, this.config.acquireTimeout);
      this.waitQueue.push({resolve, reject, timeout});
      this.updateMetrics();
    });
  }

  async release(conn: T): Promise<void> {
    if (!this.inUseConnections.delete(conn)) return;
    if (this.isShuttingDown) { await this.destroyConnection(conn); this.checkShutdown(); return; }
    const waiter = this.waitQueue.shift();
    if (waiter) { clearTimeout(waiter.timeout); this.inUseConnections.add(conn); waiter.resolve(conn); this.updateMetrics(); return; }
    this.idleConnections.push({conn, lastUsed: Date.now()});
    this.updateMetrics();
  }

  private removeFromQueue(timeout: NodeJS.Timeout): void {
    const idx = this.waitQueue.findIndex(w => w.timeout === timeout);
    if (idx !== -1) { this.waitQueue.splice(idx, 1); this.updateMetrics(); }
  }

  private startIdleReaper(): void {
    this.reaperInterval = setInterval(() => {
      const now = Date.now();
      const toRemove: T[] = [];
      for (const item of this.idleConnections) {
        if (now - item.lastUsed > this.config.idleTimeout && this.metrics.poolSize > this.config.minConnections) toRemove.push(item.conn);
      }
      for (const conn of toRemove) {
        const idx = this.idleConnections.findIndex(i => i.conn === conn);
        if (idx !== -1) { this.idleConnections.splice(idx, 1); this.destroyConnection(conn); }
      }
      this.updateMetrics();
    }, Math.min(this.config.idleTimeout, 30000));
  }

  async shutdown(): Promise<void> {
    this.isShuttingDown = true;
    if (this.reaperInterval) clearInterval(this.reaperInterval);
    for (const w of this.waitQueue) { clearTimeout(w.timeout); w.reject(new Error('Pool shutting down')); }
    this.waitQueue = [];
    for (const item of this.idleConnections) await this.destroyConnection(item.conn);
    this.idleConnections = [];
    await this.checkShutdown();
  }

  private async checkShutdown(): Promise<void> {
    if (this.isShuttingDown && this.inUseConnections.size === 0) { /* done */ }
  }

  private updateMetrics(): void {
    this.metrics.idleCount = this.idleConnections.length;
    this.metrics.inUseCount = this.inUseConnections.size;
    this.metrics.waitQueueLength = this.waitQueue.length;
  }

  getMetrics(): PoolMetrics { return {...this.metrics}; }
}
